export function getVenuesByDestination(destinationId: string): Venue[] {
  return venues.filter(v => v.destinationId === destinationId)
}

export function getVenuesByCategory(destinationId: string, category: string): Venue[] {
  return venues.filter(v => v.destinationId === destinationId && v.category === category)
}

export function getVenueById(id: string): Venue | undefined {
  return venues.find(v => v.id === id)
}
